   302→// of the status feature.
   303→func dropDeallocatedStatusDevices(newClaim, oldClaim *resource.ResourceClaim) {
   304→	if !utilfeature.DefaultFeatureGate.Enabled(features.DRAResourceClaimDeviceStatus) && !isDRAResourceClaimDeviceStatusInUse(oldClaim) {
