   358→	if allocation := claim.Status.Allocation; allocation != nil {
   359→		for _, result := range allocation.Devices.Results {
   360→			if result.ShareID != nil || result.ConsumedCapacity != nil {
   361→				return true
   362→			}
   363→		}
   364→	}
